JS-слой вообще не знает, с какой платформы пришли данные. И это прекрасно. Никаких
if (Platform.OS === 'ios')
, никаких отдельных парсеров под Android. Добавить новое поле? Поменяли формирование JSON в двух местах — и всё, JS просто начинает его читать.
iOS: два входа — одно хранилище
NotificationService Extension
Расширение запускается системой при получении пуша с флагом
mutable-content: 1
, даже если приложение убито. Именно здесь мы и ловим момент, пока никто не мешает. Метод
didReceive
дёргает
saveNotification
, та формирует JSON и кладёт его в общий
UserDefaults
через App Group.
final class NotificationService: UNNotificationServiceExtension {
 static let suiteName = "group.cloud.Mindbox.com.example.exampleapp"
 static let notificationsKey = "notifications"
 private lazy var mindboxService = MindboxNotificationService()

 override func didReceive(_ request: UNNotificationRequest,
 withContentHandler contentHandler: @escaping (UNNotificationContent) -> Void) {
 saveNotification(request: request)
 mindboxService.didReceive(request, withContentHandler: contentHandler)
 }

 private func saveNotification(request: UNNotificationRequest) {
 guard let ud = UserDefaults(suiteName: NotificationService.suiteName) else { return }
 guard let pushData = mindboxService.getMindboxPushData(userInfo: request.content.userInfo) else { return }

 let storedJson = createStoredPushJson(from: pushData)

 var notifications = ud.array(forKey: NotificationService.notificationsKey) as? [String] ?? []
 if !notifications.contains(storedJson) {
 notifications.append(storedJson)
 ud.set(notifications, forKey: NotificationService.notificationsKey)
 ud.synchronize()
 }
 }

 private func createStoredPushJson(from pushData: MindboxPushData) -> String {
 let dict: [String: Any] = [
 "uniqueKey": pushData.uniqueKey ?? UUID().uuidString,
 "title": pushData.aps?.alert?.title ?? "",
 "description": pushData.aps?.alert?.body ?? "",
 "imageUrl": pushData.imageUrl ?? "",
 "pushLink": pushData.clickUrl ?? "",
 "payload": pushData.payload ?? "",
 "receivedAt": Date().timeIntervalSince1970
 ]
 guard let data = try? JSONSerialization.data(withJSONObject: dict),
 let json = String(data: data, encoding: .utf8) else { return "{}" }
 return json
 }
}
Обратите внимание: проверка
if !notifications.contains(storedJson)
— это защита от дубликатов. Не раз сталкивался с тем, что один пуш может дёрнуть сохранение дважды, и лучше перестраховаться на этапе записи, чем потом разбираться в UI.
