private func saveMindboxPush(_ userInfo: [AnyHashable: Any]) {
 guard Mindbox.shared.isMindboxPush(userInfo: userInfo) else { return }
 guard let pushData = Mindbox.shared.getMindboxPushData(userInfo: userInfo) else { return }

 let ud = UserDefaults(suiteName: "group.cloud.Mindbox.com.example.exampleapp")
 let storedJson = createStoredPushJson(from: pushData)

 var current = ud?.array(forKey: "notifications") as? [String] ?? []
 if !current.contains(storedJson) {
 current.append(storedJson)
 ud?.set(current, forKey: "notifications")
 ud?.synchronize()
 }
}
Важный момент: оба метода пишут в один и тот же ключ
notifications
в общем
UserDefaults
