class MindboxFirebaseMessagingService: FirebaseMessagingService() {
 override fun onMessageReceived(remoteMessage: RemoteMessage) {
 Mindbox.handleRemoteMessage(applicationContext, remoteMessage, ...)
 val mindboxMessage = MindboxFirebase.convertToMindboxRemoteMessage(remoteMessage)
 if (mindboxMessage != null) {
 (applicationContext as MainApplication).saveNotification(mindboxMessage)
 }
 }
}
MainApplication.kt
А вот и сам метод
saveNotification
. Делает ровно то же, что и iOS: формирует JSON по единому контракту и пишет в
SharedPreferences
