Помните, я обещал, что JS будет простым? Вот, смотрите:
interface StoredPush {
 uniqueKey: string;
 title: string;
 description: string;
 imageUrl?: string;
 pushLink?: string;
 payload?: string;
 receivedAt: number;
}

const NotificationCenterScreen = () => {
 const [notifications, setNotifications] = useState<StoredPush[]>([]);

 const loadNotifications = async () => {
 const result = await NotificationModule.getNotifications();
 const pushes: StoredPush[] = JSON.parse(result)
 .map((str: string) => JSON.parse(str))
 .reverse();
 setNotifications(pushes);
 };

 useEffect(() => {
 loadNotifications();
 const subscription = DeviceEventEmitter.addListener(
 'newNotification', loadNotifications
 );
 return () => subscription.remove();
 }, []);

 return <FlatList data={notifications} ... />;
};
